def _build_documents() -> list[Document]:
    return [
        Document(
            page_content=chunk["text"],
            metadata={"source": chunk["source"], "category": chunk["category"]},
        )
        for chunk in AGRI_KNOWLEDGE
    ]


def load_vector_store(force_rebuild: bool = False) -> FAISS:
    """Return a FAISS vector store – loads from disk or rebuilds."""
    embeddings = HuggingFaceEmbeddings(
        model_name=EMBEDDING_MODEL,
        model_kwargs={"device": "cpu"},
        encode_kwargs={"normalize_embeddings": True},
    )

    if not force_rebuild and (INDEX_DIR / "index.faiss").exists():
        logger.info("Loading FAISS index from disk …")
        return FAISS.load_local(
            str(INDEX_DIR), embeddings, allow_dangerous_deserialization=True
        )

    logger.info("Building FAISS index from knowledge base …")
    docs = _build_documents()
    store = FAISS.from_documents(docs, embeddings)
    INDEX_DIR.mkdir(parents=True, exist_ok=True)
    store.save_local(str(INDEX_DIR))
    logger.info(f"FAISS index saved to {INDEX_DIR}")
    return store


def retrieve_context(query: str, store: FAISS, k: int = 4) -> str:
    """Return top-k relevant chunks as a formatted context string."""
    docs = store.similarity_search(query, k=k)
    if not docs:
        return "No relevant agronomic data found in knowledge base."
    parts = []
    for i, doc in enumerate(docs, 1):
        parts.append(
            f"[{i}] ({doc.metadata.get('source', 'Unknown')}) {doc.page_content}"
        )
    return "\n\n".join(parts)
